const folders = $input.all().map(item => item.json);

// Practice configuration with EHR type for proper parsing
const practiceConfig = {
  'VPN-019': { name: 'Burbank Family Medicine', ehr: 'drchrono' },
  'VPN-020': { name: 'Glendale Primary Care', ehr: 'drchrono' },
  'VPN-021': { name: 'Pasadena Internal Med', ehr: 'drchrono' },
  'VPN-022': { name: 'Arcadia Family Health', ehr: 'drchrono' },
  'VPN-023': { name: 'Monrovia Primary', ehr: 'drchrono' },
  'VPN-024': { name: 'Duarte Medical Group', ehr: 'drchrono' },
  'VPN-025': { name: 'Azusa Family Practice', ehr: 'drchrono' },
  'VPN-026': { name: 'Covina Health Center', ehr: 'drchrono' },
  'VPN-027': { name: 'West Covina Primary', ehr: 'practice-fusion' },
  'VPN-028': { name: 'Pomona Family Medicine', ehr: 'practice-fusion' },
  'VPN-029': { name: 'Claremont Medical', ehr: 'practice-fusion' },
  'VPN-030': { name: 'La Verne Primary', ehr: 'practice-fusion' },
  'VPN-031': { name: 'San Dimas Health', ehr: 'practice-fusion' },
  'VPN-032': { name: 'Glendora Family', ehr: 'practice-fusion' },
  'VPN-033': { name: 'Diamond Bar Medical', ehr: 'practice-fusion' },
  'VPN-034': { name: 'Walnut Primary Care', ehr: 'kareo' },
  'VPN-035': { name: 'Rowland Heights Med', ehr: 'kareo' },
  'VPN-036': { name: 'Hacienda Heights', ehr: 'kareo' },
  'VPN-037': { name: 'La Puente Family', ehr: 'kareo' },
  'VPN-038': { name: 'Industry Health', ehr: 'kareo' },
  'VPN-039': { name: 'Baldwin Park Med', ehr: 'kareo' },
  'VPN-040': { name: 'El Monte Primary', ehr: 'elation' },
  'VPN-041': { name: 'South El Monte', ehr: 'elation' },
  'VPN-042': { name: 'Rosemead Family', ehr: 'elation' },
  'VPN-043': { name: 'Temple City Health', ehr: 'elation' },
  'VPN-044': { name: 'San Gabriel Medical', ehr: 'elation' },
  'VPN-045': { name: 'Alhambra Primary', ehr: 'elation' },
  'VPN-046': { name: 'Monterey Park Med', ehr: 'elation' }
};

// Filter for folders with new files
const practicesWithUploads = folders
  .filter(folder => folder.type === 'directory' && practiceConfig[folder.name])
  .map(folder => ({
    json: {
      practiceId: folder.name,
      ...practiceConfig[folder.name],
      folderPath: `/vpn/practice-uploads/${folder.name}/`
    }
  }));

return practicesWithUploads;

const rows = $input.all().map(item => item.json);
const practice = $('Process Each Practice').item.json;
const fileName = $('Filter CSV Files').item.json.name.toLowerCase();

// Detect file type from name or columns
let fileType = 'unknown';
const firstRow = rows[0] || {};
const columns = Object.keys(firstRow).map(c => c.toLowerCase());

if (fileName.includes('patient') || columns.includes('patient_id') || columns.includes('mrn')) {
  fileType = 'Patient';
} else if (fileName.includes('condition') || fileName.includes('diagnosis') || columns.includes('icd_code')) {
  fileType = 'Condition';
} else if (fileName.includes('lab') || fileName.includes('result') || columns.includes('loinc')) {
  fileType = 'Observation';
} else if (fileName.includes('med') || columns.includes('ndc') || columns.includes('rxnorm')) {
  fileType = 'MedicationRequest';
} else if (fileName.includes('encounter') || fileName.includes('visit')) {
  fileType = 'Encounter';
} else if (fileName.includes('procedure') || columns.includes('cpt')) {
  fileType = 'Procedure';
} else if (fileName.includes('immunization') || fileName.includes('vaccine') || columns.includes('cvx')) {
  fileType = 'Immunization';
}

return rows.map(row => ({
  json: {
    ...row,
    _metadata: {
      practiceId: practice.practiceId,
      practiceName: practice.name,
      ehr: practice.ehr,
      fileType: fileType,
      fileName: fileName
    }
  }
}));

const row = $input.item.json;
const meta = row._metadata;

// EHR-specific column mapping
const columnMaps = {
  'drchrono': {
    mrn: 'chart_id',
    firstName: 'first_name',
    lastName: 'last_name',
    dob: 'date_of_birth',
    gender: 'gender',
    phone: 'cell_phone',
    email: 'email'
  },
  'practice-fusion': {
    mrn: 'PatientID',
    firstName: 'FirstName',
    lastName: 'LastName',
    dob: 'DOB',
    gender: 'Sex',
    phone: 'Phone',
    email: 'Email'
  },
  'kareo': {
    mrn: 'patient_id',
    firstName: 'first',
    lastName: 'last',
    dob: 'birth_date',
    gender: 'sex',
    phone: 'phone_number',
    email: 'email_address'
  },
  'elation': {
    mrn: 'patient_id',
    firstName: 'given_name',
    lastName: 'family_name',
    dob: 'birthdate',
    gender: 'sex',
    phone: 'phone',
    email: 'email'
  }
};

const cols = columnMaps[meta.ehr] || columnMaps['drchrono'];

// Normalize gender
const genderMap = {
  'm': 'male', 'male': 'male', 'f': 'female', 'female': 'female',
  'o': 'other', 'other': 'other', 'u': 'unknown', 'unknown': 'unknown'
};
const rawGender = (row[cols.gender] || '').toLowerCase();

const patient = {
  resourceType: 'Patient',
  id: `${meta.practiceId}-${row[cols.mrn]}`,
  meta: {
    source: `${meta.ehr} via n8n`,
    tag: [{
      system: 'http://vpn.example.com/practice',
      code: meta.practiceId,
      display: meta.practiceName
    }]
  },
  identifier: [{
    system: `http://vpn.example.com/${meta.practiceId}/mrn`,
    value: row[cols.mrn]
  }],
  name: [{
    family: row[cols.lastName],
    given: [row[cols.firstName]]
  }],
  gender: genderMap[rawGender] || 'unknown',
  birthDate: row[cols.dob]
};

if (row[cols.phone]) {
  patient.telecom = [{ system: 'phone', value: row[cols.phone] }];
}
if (row[cols.email]) {
  patient.telecom = patient.telecom || [];
  patient.telecom.push({ system: 'email', value: row[cols.email] });
}

return { json: patient };

const row = $input.item.json;
const meta = row._metadata;

// Find ICD code and description columns (varies by EHR)
const icdCode = row.icd_code || row.ICD10 || row.diagnosis_code || row.code;
const icdDesc = row.diagnosis || row.description || row.name || row.diagnosis_name;
const mrn = row.patient_id || row.PatientID || row.chart_id || row.mrn;
const status = (row.status || 'active').toLowerCase();

const condition = {
  resourceType: 'Condition',
  id: `${meta.practiceId}-cond-${mrn}-${icdCode.replace(/\./g, '')}`,
  meta: {
    source: `${meta.ehr} via n8n`,
    tag: [{
      system: 'http://vpn.example.com/practice',
      code: meta.practiceId
    }]
  },
  clinicalStatus: {
    coding: [{
      system: 'http://terminology.hl7.org/CodeSystem/condition-clinical',
      code: status.includes('resolv') || status.includes('inact') ? 'resolved' : 'active'
    }]
  },
  code: {
    coding: [{
      system: 'http://hl7.org/fhir/sid/icd-10-cm',
      code: icdCode,
      display: icdDesc
    }],
    text: icdDesc
  },
  subject: {
    reference: `Patient/${meta.practiceId}-${mrn}`
  },
  onsetDateTime: row.onset_date || row.diagnosis_date || row.date
};

return { json: condition };

const row = $input.item.json;
const meta = row._metadata;

const mrn = row.patient_id || row.PatientID || row.chart_id || row.mrn;
const loincCode = row.loinc || row.loinc_code || row.code;
const testName = row.test_name || row.name || row.description;
const resultValue = row.result || row.value;
const resultUnit = row.unit || row.units || '';
const resultDate = row.date || row.result_date || row.collected_date;

const observation = {
  resourceType: 'Observation',
  id: `${meta.practiceId}-obs-${mrn}-${loincCode}-${resultDate.replace(/[^0-9]/g, '')}`,
  meta: {
    source: `${meta.ehr} via n8n`,
    tag: [{
      system: 'http://vpn.example.com/practice',
      code: meta.practiceId
    }]
  },
  status: 'final',
  category: [{
    coding: [{
      system: 'http://terminology.hl7.org/CodeSystem/observation-category',
      code: 'laboratory'
    }]
  }],
  code: {
    coding: [{
      system: 'http://loinc.org',
      code: loincCode,
      display: testName
    }],
    text: testName
  },
  subject: {
    reference: `Patient/${meta.practiceId}-${mrn}`
  },
  effectiveDateTime: resultDate
};

// Handle numeric vs string results
const numValue = parseFloat(resultValue);
if (!isNaN(numValue)) {
  observation.valueQuantity = {
    value: numValue,
    unit: resultUnit,
    system: 'http://unitsofmeasure.org'
  };
} else {
  observation.valueString = resultValue;
}

return { json: observation };

const resources = $input.all().map(item => item.json);
const BATCH_SIZE = 100;
const batches = [];

for (let i = 0; i < resources.length; i += BATCH_SIZE) {
  const batch = resources.slice(i, i + BATCH_SIZE);
  batches.push({
    json: {
      resourceType: 'Bundle',
      type: 'batch',
      timestamp: new Date().toISOString(),
      entry: batch.map(r => ({
        resource: r,
        request: { method: 'PUT', url: `${r.resourceType}/${r.id}` }
      }))
    }
  });
}

return batches;
